    'photosnail-public': {
      summary: 'Ранний web-проект PhotoSnail вокруг систем управляемого движения камеры и экспериментов с медиа-презентацией.',
      details: 'Ранний публичный web-проект, связанный с PhotoSnail R&D: системы движения камеры, идеи отслеживания объекта и медиа-презентационные эксперименты вокруг автоматизированной съёмки.',
    },
